def clean_date_series(series: pd.Series) -> pd.Series:
    s = series.astype(str).str.strip()
    s = s.where(s.ne('') & ~s.str.lower().isin(['nan', 'none', 'null', 'nat']), None)
    dt = pd.to_datetime(s, errors='coerce', format='mixed', dayfirst=False)
    dt.loc[(dt.dt.year < 1901) | (dt.dt.year > 2099)] = pd.NaT
    return dt.dt.strftime('%Y-%m-%d').fillna('').astype(str)

from decimal import Decimal, InvalidOperation
import re
sci_regex = re.compile(r'^[+-]?\d+(?:\.\d+)?[eE][+-]?\d+$')
def fix_scientific_cell(text: str) -> str:
    if not text or not sci_regex.match(text):
        return text
    try:
        dec_val = Decimal(text)
        if dec_val % 1 == 0:
            return format(dec_val.quantize(Decimal('1')), 'f')
        return format(dec_val, 'f').rstrip('0').rstrip('.')
    except InvalidOperation:
        return text

def strip_trailing_decimal_zeros(val: str) -> str:
    s = str(val).strip()
    if re.match(r'^\d+\.0+$', s):
        return s.split('.')[0]
    return s

NULL_TOKENS = {'nan', 'n/a', 'na', 'none', '#n/a', 'null', 'empty', 'n.a.', '-', 'pending', 'not provided', 'nat'}
def clean_cell_value(value) -> str:
    if value is None or (isinstance(value, float) and pd.isna(value)):
        return ''
    s = str(value).strip()
    if s.lower() in NULL_TOKENS:
        return ''
    return s

def strip_and_collapse_whitespace(series: pd.Series) -> pd.Series:
    s = series.astype(str).str.strip()
    s = s.str.replace(r'[\r\n\t]+', ' ', regex=True)
    s = s.str.replace(r' +', ' ', regex=True)
    return s.str.strip()

