def parse_office_hours(series: pd.Series) -> pd.DataFrame:
    """Parse multi-line office hours text into 14 open/close time columns (Mon-Sun).
    Input: 'Monday: 9:00 AM to 5:00 PM\nTuesday: 9:00 AM to 5:00 PM'
    Output: DataFrame with openTimeMon=09:00, closeTimeMon=17:00, ..., openTimeSun, closeTimeSun
    """
    DAYS = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    DAY_ALIASES = {
        "MONDAY": "Mon", "TUESDAY": "Tue", "WEDNESDAY": "Wed", "THURSDAY": "Thu",
        "FRIDAY": "Fri", "SATURDAY": "Sat", "SUNDAY": "Sun",
        "MON": "Mon", "TUE": "Tue", "WED": "Wed", "THU": "Thu",
        "FRI": "Fri", "SAT": "Sat", "SUN": "Sun",
    }
    TIME_RE = re.compile(r"(\d{1,2}):?(\d{2})?\s*(AM|PM)?", re.I)

    def parse_time(time_str):
        if not time_str:
            return ""
        m = TIME_RE.match(time_str.strip())
        if not m:
            return ""
        hour, minute, meridiem = int(m.group(1)), int(m.group(2) or 0), (m.group(3) or "").upper()
        if meridiem == "PM" and hour != 12:
            hour += 12
        elif meridiem == "AM" and hour == 12:
            hour = 0
        return f"{hour:02d}:{minute:02d}"

    result = pd.DataFrame(index=series.index)
    for day in DAYS:
        result[f"openTime{day}"] = ""
        result[f"closeTime{day}"] = ""

    for idx, val in series.items():
        if pd.isna(val) or not str(val).strip():
            continue
        for line in str(val).replace(";", "\n").split("\n"):
            line = line.strip()
            if not line:
                continue
            parts = re.split(r"[:–-]", line, maxsplit=1)
            if len(parts) < 2:
                continue
            day_key = parts[0].strip().upper()
            day = DAY_ALIASES.get(day_key)
            if not day:
                continue
            time_range = parts[1].strip()
            times = re.split(r"\bto\b|\-", time_range, flags=re.I)
            if len(times) >= 2:
                result.at[idx, f"openTime{day}"] = parse_time(times[0].strip())
                result.at[idx, f"closeTime{day}"] = parse_time(times[1].strip())
            elif len(times) == 1:
                result.at[idx, f"openTime{day}"] = parse_time(times[0].strip())
    return result

def duplicate_plan_rows(df: pd.DataFrame,
                        plan_fields: list = None) -> pd.DataFrame:
    """Duplicate rows for multiple plans encoded as numbered columns.
    PlanName, PlanName.1, PlanName.2 → 3 rows each with one plan name.
    All non-plan columns are duplicated in each row.
    """
    if plan_fields is None:
        plan_fields = ["planName", "planEffectiveDate", "planTermDate", "planNPINumber"]

    # Find plan column groups (base + numbered variants)
    base_pattern = re.compile(r"^(" + "|".join(plan_fields) + r")(\.(\d+))?$", re.I)
    grouped = {}
    non_plan_cols = []
    for col in df.columns:
        m = base_pattern.match(col)
        if m:
            base = m.group(1).lower()
            n = int(m.group(3)) if m.group(3) else 0
            grouped.setdefault(base, {})[n] = col
        else:
            non_plan_cols.append(col)

    if not grouped:
        return df

    # Max plan count
    max_plans = max(max(v.keys()) for v in grouped.values()) + 1
    rows_out = []
    for _, row in df.iterrows():
        for plan_idx in range(max_plans):
            plan_vals = {}
            for base, idx_map in grouped.items():
                col = idx_map.get(plan_idx)
                val = row[col] if col and col in row.index else ""
                plan_vals[base] = val
            # Skip if all plan fields are empty
            if not any(str(v).strip() for v in plan_vals.values()):
                continue
            new_row = {c: row[c] for c in non_plan_cols if c in row.index}
            new_row.update(plan_vals)
            rows_out.append(new_row)
    return pd.DataFrame(rows_out, columns=non_plan_cols + list(grouped.keys())) if rows_out else df.iloc[0:0]

def remove_sparse_rows(df: pd.DataFrame, threshold: float = 0.80) -> pd.DataFrame:
    """Remove rows where more than threshold fraction of columns are empty/null.
    Threshold default 0.80 means rows with >80% empty columns are removed.
    Empty = NaN, None, empty string, or null-equivalent values.
    """
    NULL_TOKENS = {"", "nan", "none", "null", "n/a", "na", "#n/a", "not applicable"}

    def is_empty(val):
        if val is None or (isinstance(val, float) and pd.isna(val)):
            return True
        return str(val).strip().lower() in NULL_TOKENS

    null_ratio = df.apply(lambda row: sum(is_empty(v) for v in row) / max(len(row), 1), axis=1)
    return df[null_ratio < threshold].reset_index(drop=True)

def remove_exact_duplicates(df: pd.DataFrame) -> pd.DataFrame:
    """Remove exact duplicate rows, keeping first occurrence.
    Normalizes strings to lowercase+stripped before comparison.
    """
    normalized = df.apply(lambda col: col.map(
        lambda v: str(v).strip().lower() if v is not None and not (isinstance(v, float) and pd.isna(v)) else ""
    ))
    return df[~normalized.duplicated(keep="first")].reset_index(drop=True)

def sanitize_bq_column_name(name: str) -> str:
    clean = re.sub(r'[^A-Za-z0-9_]', '_', str(name))
    if not re.match(r'^[A-Za-z_]', clean):
        clean = '_' + clean
    clean = re.sub(r'_+', '_', clean)
    return clean.strip('_')[:300]

def medicare_id_hyphen_removal(series: pd.Series) -> pd.Series:
    """Remove hyphens from Medicare Beneficiary Identifier (MBI) values.
    '7N-28-41' → '7N2841'
    Also handles Medicare legacy HIC numbers.
    """
    return series.apply(
        lambda v: re.sub(r"-", "", str(v).strip()) if v and str(v).strip().lower() not in ("nan", "none", "") else ""
    )
